#import "FullScreenImageViewController.h"

@interface FullScreenImageViewController ()

@property (nonatomic, strong) UIImageView *imageView;

@end

@implementation FullScreenImageViewController {
    CGFloat _currentScale;      // 当前缩放比例
    CGFloat _lastScale;         // 上次手势结束时的缩放比例
}

- (void)viewDidLoad {
    [super viewDidLoad];
    _currentScale = 1.0f;
    _lastScale = 1.0f;
    [self setUpUI];
    [self setUpEvents];
}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    self.imageView.transform = CGAffineTransformMakeScale(0.8, 0.8); // 初始缩小
    [UIView animateWithDuration:0.3 animations:^{
        self.imageView.transform = CGAffineTransformIdentity; // 恢复原大小
    }];
}


#pragma mark - setUp

- (void)setUpUI {
    self.view.backgroundColor = [UIColor blackColor];
    [self addAllSubviews];
    [self addAllConstrains];
}

- (void)addAllSubviews {
    [self.view addSubview:self.imageView];
}

- (void)addAllConstrains {
    [_imageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.view);
    }];
}


#pragma mark - events

- (void)setUpEvents {
    // 点击退出手势
    UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(dismissFullscreen)];
    [self.imageView addGestureRecognizer:tap];

    // 双指缩放手势
    UIPinchGestureRecognizer *pinch = [[UIPinchGestureRecognizer alloc] initWithTarget:self action:@selector(handlePinch:)];
    [self.imageView addGestureRecognizer:pinch];
}

- (void)dismissFullscreen {
    [self dismissViewControllerAnimated:YES completion:nil];
}

- (void)handlePinch:(UIPinchGestureRecognizer *)gesture {
    // 手势开始：重置缩放基准
    if (gesture.state == UIGestureRecognizerStateBegan) {
        _lastScale = _currentScale;
        gesture.scale = 1.0; // 重置为基准比例
    }

    // 手势变化：计算新缩放比例
    if (gesture.state == UIGestureRecognizerStateChanged) {
        CGFloat newScale = gesture.scale * _lastScale;

        // 限制缩放范围（0.5倍 ~ 4倍）
        newScale = MAX(0.5f, MIN(newScale, 4.0f));
        _currentScale = newScale;

        // 应用缩放变换
        self.imageView.transform = CGAffineTransformMakeScale(newScale, newScale);
    }

    // 手势结束：添加弹性动画
    if (gesture.state == UIGestureRecognizerStateEnded) {
        __weak typeof(self) weakSelf = self; // 弱引用 self
        [UIView animateWithDuration:0.3
                              delay:0
             usingSpringWithDamping:0.5
              initialSpringVelocity:0.5
                            options:UIViewAnimationOptionCurveEaseOut
                         animations:^{
            __strong typeof(weakSelf) strongSelf = weakSelf; // 强引用弱指针
            if (strongSelf) {
                strongSelf.imageView.transform = CGAffineTransformMakeScale(strongSelf->_currentScale, strongSelf->_currentScale);
            }
        } completion:nil];
    }
}


#pragma mark - lazy load

- (UIImageView *)imageView {
    if (!_imageView) {
        _imageView = [[UIImageView alloc] initWithImage:self.fullImage];
        _imageView.contentMode = UIViewContentModeScaleAspectFit;
        _imageView.userInteractionEnabled = YES; // 启用手势
    }
    return _imageView;
}


@end

