- (void)imagePickerController:(UIImagePickerController *)picker didFinishPickingMediaWithInfo:(NSDictionary<UIImagePickerControllerInfoKey, id> *)info {
    [picker dismissViewControllerAnimated:YES completion:nil];

    // Get selected image
    self.originalImage = info[UIImagePickerControllerOriginalImage];
    if (self.originalImage) {
        // Display in PictureHandleView
        self.handleView.pictureView.image = self.originalImage;
        self.handleView.tipLabel.hidden = YES;
        [self updateWatermark];
    }
}

- (void)imagePickerControllerDidCancel:(UIImagePickerController *)picker {
    [picker dismissViewControllerAnimated:YES completion:nil];
}

- (void)showPermissionAlert {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Photo Library Access Denied"
                                                                   message:@"Please enable access in Settings > Privacy > Photos"
                                                            preferredStyle:UIAlertControllerStyleAlert];
    UIAlertAction *settingAction = [UIAlertAction actionWithTitle:@"Settings" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        [[UIApplication sharedApplication] openURL:[NSURL URLWithString:UIApplicationOpenSettingsURLString]
                                           options:@{}
                                 completionHandler:nil];
    }];
    UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleCancel handler:nil];
    [alert addAction:settingAction];
    [alert addAction:cancelAction];
    [self presentViewController:alert animated:YES completion:nil];
}

#pragma mark - Save Image Operations

- (void)performSaveImage:(UIImage *)image {
    [[PHPhotoLibrary sharedPhotoLibrary] performChanges:^{
        [PHAssetChangeRequest creationRequestForAssetFromImage:image];
    } completionHandler:^(BOOL success, NSError * _Nullable error) {
        dispatch_async(dispatch_get_main_queue(), ^{
            if (success) {
                [self showAlertWithTitle:@"Save Success" message:@"Image saved to photo library"];
            } else {
                NSString *errorMsg = [NSString stringWithFormat:@"Error: %@", error.localizedDescription];
                [self showAlertWithTitle:@"Save Failed" message:errorMsg];
            }
        });
    }];
}

#pragma mark - Alert

- (void)showAlertWithTitle:(NSString *)title message:(NSString *)message {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:title
                                                                   message:message
                                                            preferredStyle:UIAlertControllerStyleAlert];
    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"OK" style:UIAlertActionStyleDefault handler:nil];
    [alert addAction:okAction];
    [self presentViewController:alert animated:YES completion:nil];
}

- (void)presentFullScreenPreview {
    if (!self.handleView.pictureView.image) {
        [self showAlertWithTitle:@"提示" message:@"请先选择图片"];
        return;
    }
    FullScreenImageViewController *fullScreenVC = [[FullScreenImageViewController alloc] init];
    fullScreenVC.fullImage = self.handleView.pictureView.image;
    fullScreenVC.modalPresentationStyle = UIModalPresentationFullScreen;
    fullScreenVC.modalTransitionStyle = UIModalTransitionStyleCrossDissolve;
    [self presentViewController:fullScreenVC animated:YES completion:nil];
}

#pragma mark - Watermark

- (void)updateWatermark {
    if (!self.originalImage) {
        self.handleView.pictureView.image = self.originalImage;
        return;
    }

    NSString *watermarkText = self.textField.text;
    UIColor *color = self.colorSelectView.colorButton.backgroundColor;
    CGFloat opacity = self.opacitySliderView.value;
    CGFloat fontSize = self.textSizeSliderView.value;
    CGFloat angle = self.angleSliderView.value;

    if (watermarkText.length == 0) {
        self.handleView.pictureView.image = self.originalImage;
        return;
    }

    UIFont *font = [UIFont systemFontOfSize:fontSize];

    // Async watermark generation
    __weak typeof(self) weakSelf = self;
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        UIImage *watermarkedImage = [weakSelf.originalImage addWatermarkWithText:watermarkText
                                                                            font:font
                                                                           color:color
                                                                         opacity:opacity
                                                                           angle:angle];

        dispatch_async(dispatch_get_main_queue(), ^{
            weakSelf.handleView.pictureView.image = watermarkedImage;
        });
    });
}

