- (NSString *)modeFileAtIndex:(NSInteger)index {
    switch (index) {
        case 0:
            return @"violin.mp3";
        case 1:
            return @"piano.mp3";
        case 2:
            return @"guitar.mp3";
        default:
            return @"violin.mp3";
    }
}

- (void)selectModeAtIndex:(NSInteger)index {
    NSInteger validIndex = MAX(0, MIN(index, 2));
    self.selectedModeIndex = validIndex;
    self.mode = [self modeFileAtIndex:validIndex];

    self.xueshanbotton.selected = (validIndex == 0);
    self.jingmibotton.selected = (validIndex == 1);
    self.caoyuanbotton.selected = (validIndex == 2);
}

- (void)updatePlaybackState:(BOOL)isPlaying currentIndex:(NSInteger)currentIndex {
    [self selectModeAtIndex:currentIndex];

    [self updatePlayIcon:self.Selected1 isPlaying:(isPlaying && currentIndex == 0)];
    [self updatePlayIcon:self.Selected2 isPlaying:(isPlaying && currentIndex == 1)];
    [self updatePlayIcon:self.Selected3 isPlaying:(isPlaying && currentIndex == 2)];
}

- (void)modeShouldUpdate:(UIButton *)button {
    if (button == _xueshanbotton) {
        [self selectModeAtIndex:0];
