- (void)requestPhotoLibraryAccess {
    PHAuthorizationStatus status = [PHPhotoLibrary authorizationStatus];
    if (status == PHAuthorizationStatusAuthorized
#ifdef __IPHONE_14_0
        || status == PHAuthorizationStatusLimited
#endif
        ) {
        [self openImagePicker]; // Already authorized
    } else if (status == PHAuthorizationStatusNotDetermined) {
        [PHPhotoLibrary requestAuthorization:^(PHAuthorizationStatus status) {
            if (status == PHAuthorizationStatusAuthorized
#ifdef __IPHONE_14_0
                || status == PHAuthorizationStatusLimited
#endif
                ) {
                dispatch_async(dispatch_get_main_queue(), ^{
                    [self openImagePicker];
                });
            }
        }];
    } else {
        // Access denied
        [self showPermissionAlert];
    }
}

- (void)openImagePicker {
    UIImagePickerController *imagePicker = [[UIImagePickerController alloc] init];
    imagePicker.sourceType = UIImagePickerControllerSourceTypePhotoLibrary;
    imagePicker.delegate = self;
    [self presentViewController:imagePicker animated:YES completion:nil];
}

- (void)saveImageToPhotoLibrary {
    UIImage *imageToSave = self.handleView.pictureView.image;
    if (!imageToSave) {
        [self showAlertWithTitle:@"Save Failed" message:@"Please select an image first"];
        return;
    }
    PHAuthorizationStatus status = [PHPhotoLibrary authorizationStatus];
    switch (status) {
        case PHAuthorizationStatusAuthorized: {
            [self performSaveImage:imageToSave];
            break;
        }
#ifdef __IPHONE_14_0
        case PHAuthorizationStatusLimited: {
            [self performSaveImage:imageToSave];
            break;
        }
#endif
        case PHAuthorizationStatusNotDetermined: {
            [PHPhotoLibrary requestAuthorization:^(PHAuthorizationStatus newStatus) {
                if (newStatus == PHAuthorizationStatusAuthorized
#ifdef __IPHONE_14_0
                    || newStatus == PHAuthorizationStatusLimited
#endif
                    ) {
                    dispatch_async(dispatch_get_main_queue(), ^{
                        [self performSaveImage:imageToSave];
                    });
                }
            }];
            break;
        }
        default: {
            [self showPermissionAlert];
            break;
        }
    }

