- (NSURL *)saveImageToTempFile:(UIImage *)image {
    if (!image) { return nil; }
    NSData *imageData = UIImageJPEGRepresentation(image, 0.8);
    if (!imageData || imageData.length == 0) { return nil; }
    NSString *fileName = [NSString stringWithFormat:@"feedback_%@.jpg", NSUUID.UUID.UUIDString];
    NSString *tempPath = [NSTemporaryDirectory() stringByAppendingPathComponent:fileName];
    NSURL *tempURL = [NSURL fileURLWithPath:tempPath];
    NSError *error = nil;
    BOOL ok = [imageData writeToURL:tempURL options:NSDataWritingAtomic error:&error];
    if (!ok || error) { return nil; }
    return tempURL;
}


#pragma mark - table view

- (NSInteger)getStringWidthToCellHeight:(NSString *)string {
    // 将文本分割为行
    NSArray *lines = [string componentsSeparatedByString:@"\n"];

    // 计算空行数
    NSPredicate *isEmptyLinePredicate = [NSPredicate predicateWithBlock:^BOOL(id _Nullable evaluatedObject, NSDictionary * _Nullable bindings) {
        return ([evaluatedObject isKindOfClass:[NSString class]] && [(NSString *)evaluatedObject length] == 0);
    }];
    NSArray *emptyLines = [lines filteredArrayUsingPredicate:isEmptyLinePredicate];
    NSInteger emptyLineCount = (NSInteger)emptyLines.count;

    // 使用系统字体进行计算
    UIFont *font = [UIFont systemFontOfSize:16.0];

    // 计算实际文本的行数
    CGFloat totalTextHeight = 0.0;
    for (NSString *line in lines) {
        if (![emptyLines containsObject:line]) { // 只处理非空行
            // 使用boundingRect来计算文本占用的实际高度
            CGSize maxSize = CGSizeMake(ZOOM(260), CGFLOAT_MAX);  // 最大宽度

            CGRect textRect = [line boundingRectWithSize:maxSize
                                                 options:NSStringDrawingUsesLineFragmentOrigin
                                              attributes:@{NSFontAttributeName: font}
                                                 context:nil];
            // 每一行的高度由文本占用的高度决定
            totalTextHeight += textRect.size.height;
        }
    }

    // 计算 cell 的总高度
    CGFloat cellHeight = totalTextHeight              // 计算所有文本行的总高度
    + emptyLineCount * ZOOM(19)  // 计算空行的高度，这里空行的计算是不准确的，但是在代码里进行了去空行的操作
    + ZOOM(40);                  // 添加气泡上下的间距（已涵盖所有间距）
    NSLog(@"cellHeight:%lf",cellHeight-ZOOM(40));
    return cellHeight;
}

- (void)scrollToBottom {
    [self ensureBottomVisibleWithRetries:3 animated:YES];
}

- (void)scrollToBottomAnimated:(BOOL)animated {
    if (self.messages.count > 0) {
        [self.view layoutIfNeeded];
        [self.tableView layoutIfNeeded];
        CGFloat contentHeight = self.tableView.contentSize.height;
        CGFloat tableHeight = CGRectGetHeight(self.tableView.bounds);
        UIEdgeInsets adjustedInsets = self.tableView.adjustedContentInset;
        CGFloat targetY = MAX(-adjustedInsets.top, contentHeight - tableHeight + adjustedInsets.bottom);
        CGPoint target = CGPointMake(0, targetY);
        [self.tableView setContentOffset:target animated:animated];
    }
}

- (BOOL)isNearBottom {
    CGFloat visibleBottom = self.tableView.contentOffset.y + CGRectGetHeight(self.tableView.bounds);
    CGFloat contentBottom = self.tableView.contentSize.height + self.tableView.adjustedContentInset.bottom;
    return (contentBottom - visibleBottom) <= ZOOM(120);
}

- (void)ensureBottomVisibleWithRetries:(NSInteger)retries animated:(BOOL)animated {
    [self scrollToBottomAnimated:animated];
    if (retries <= 0) { return; }
    __weak typeof(self) weakSelf = self;
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.06 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        __strong typeof(weakSelf) strongSelf = weakSelf;
        if (!strongSelf) { return; }
        [strongSelf ensureBottomVisibleWithRetries:retries - 1 animated:NO];
    });
}

