- (CGFloat)getStringWidthToCellHeight:(NSString *)string {
    NSString *text = string ?: @"";
    CGFloat maxTextWidth = ZOOMW(280) - ZOOMW(20);
    CGRect textRect = [text boundingRectWithSize:CGSizeMake(maxTextWidth, CGFLOAT_MAX)
                                         options:(NSStringDrawingUsesLineFragmentOrigin | NSStringDrawingUsesFontLeading)
                                      attributes:@{NSFontAttributeName : [UIFont systemFontOfSize:16.0]}
                                         context:nil];
    CGFloat textHeight = ceil(textRect.size.height);
    CGFloat cellHeight = textHeight + ZOOM(40);
    return MAX(cellHeight, ZOOM(44));
}

- (CGFloat)getImageCellHeightForSize:(CGSize)imageSize {
    CGFloat ratio = (imageSize.height > 0.0f) ? (imageSize.width / imageSize.height) : 0.0f;
    CGFloat fixedWidth = (ratio > 1.0f) ? ZOOMW(220) : ZOOMW(160);
    CGFloat maxWidth = CGRectGetWidth(UIScreen.mainScreen.bounds) * 0.72f;
    CGFloat width = (ratio > 0.0f) ? MIN(fixedWidth, maxWidth) : ZOOMW(160);
    CGFloat height = (ratio > 0.0f) ? (width / ratio) : ZOOMW(180);
    return height + ZOOM(32);
}

- (void)scrollToBottom {
    NSInteger count = [ServiceMsgModel allMsgs].count;
    if (count > 0) {
        NSIndexPath *indexPath = [NSIndexPath indexPathForRow:count - 1 inSection:0];
        dispatch_async(dispatch_get_main_queue(), ^{
            [self.chatTableView scrollToRowAtIndexPath:indexPath atScrollPosition:UITableViewScrollPositionBottom animated:YES];
        });
    }
}

- (void)send:(UIButton *)sender {

    NSString *userText = self.sendView.sendTextField.text;
    if (userText.length == 0) return;

    CGFloat cellHeight = [self getStringWidthToCellHeight:userText];
    [ServiceMsgModel addMsg:[[ServiceMsgModel alloc] initWithContent:userText type:MessageTypeUser cellHeight:cellHeight]];
    self.sendView.sendTextField.text = @"";
    [self.chatTableView reloadData];
    [self scrollToBottom];

    // 延迟 0.5 秒执行自动回复
    dispatch_time_t popTime = dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC));
