        CGFloat cellHeight1 = [self getStringWidthToCellHeight:answer];
        [ServiceMsgModel addMsg:[[ServiceMsgModel alloc] initWithContent:answer type:MessageTypeService cellHeight:cellHeight1]];
        [self.chatTableView reloadData];
        [self scrollToBottom];
    });
}

- (void)openPhotoLibrary {
    if (![UIImagePickerController isSourceTypeAvailable:UIImagePickerControllerSourceTypePhotoLibrary]) {
        [SVProgressHUD showErrorWithStatus:@"相册不可用"];
        return;
    }
    UIImagePickerController *picker = [[UIImagePickerController alloc] init];
    picker.sourceType = UIImagePickerControllerSourceTypePhotoLibrary;
    picker.delegate = self;
    picker.modalPresentationStyle = UIModalPresentationFullScreen;
    [self presentViewController:picker animated:YES completion:nil];
}

- (void)imagePickerControllerDidCancel:(UIImagePickerController *)picker {
    [picker dismissViewControllerAnimated:YES completion:nil];
}

- (void)imagePickerController:(UIImagePickerController *)picker didFinishPickingMediaWithInfo:(NSDictionary<UIImagePickerControllerInfoKey,id> *)info {
    UIImage *image = info[UIImagePickerControllerEditedImage];
    if (!image) {
        image = info[UIImagePickerControllerOriginalImage];
    }
    [picker dismissViewControllerAnimated:YES completion:nil];
    if (!image) {
        [SVProgressHUD showErrorWithStatus:@"选择图片失败"];
        return;
    }
    NSString *imagePath = [self saveImageToLocalPath:image];
    if (imagePath.length == 0) {
        [SVProgressHUD showErrorWithStatus:@"保存图片失败"];
        return;
    }
    CGFloat cellHeight = [self getImageCellHeightForSize:image.size];
    ServiceMsgModel *imageMsg = [[ServiceMsgModel alloc] initWithImagePath:imagePath
                                                                      type:MessageTypeUser
                                                                 imageSize:image.size
                                                                cellHeight:cellHeight];
    [ServiceMsgModel addMsg:imageMsg];
    [self.chatTableView reloadData];
    [self scrollToBottom];

    dispatch_time_t popTime = dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC));
    dispatch_after(popTime, dispatch_get_main_queue(), ^{
        NSString *answer = @"图片已收到，我们会尽快查看后回复您。";
        CGFloat answerHeight = [self getStringWidthToCellHeight:answer];
        [ServiceMsgModel addMsg:[[ServiceMsgModel alloc] initWithContent:answer type:MessageTypeService cellHeight:answerHeight]];
        [self.chatTableView reloadData];
        [self scrollToBottom];
    });
}

- (NSString *)saveImageToLocalPath:(UIImage *)image {
    if (!image) { return @""; }
    NSData *imageData = UIImageJPEGRepresentation(image, 0.85);
    if (imageData.length == 0) { return @""; }
    NSString *directory = [ServiceMsgModel imageDirectoryPath];
    NSError *directoryError = nil;
    if (![[NSFileManager defaultManager] fileExistsAtPath:directory]) {
        [[NSFileManager defaultManager] createDirectoryAtPath:directory
                                  withIntermediateDirectories:YES
                                                   attributes:nil
                                                        error:&directoryError];
    }
    if (directoryError) { return @""; }
    NSString *fileName = [NSString stringWithFormat:@"service_%@.jpg", NSUUID.UUID.UUIDString];
    NSString *filePath = [directory stringByAppendingPathComponent:fileName];
    NSError *writeError = nil;
    BOOL success = [imageData writeToFile:filePath options:NSDataWritingAtomic error:&writeError];
    if (!success || writeError) { return @""; }
    return filePath;
}

