#import "MyViewController.h"
#import "FeedbackViewController.h"
#import "ServiceViewController.h"
#import "SettingViewController.h"

@interface MyViewController () <UICollectionViewDataSource, UICollectionViewDelegate, UICollectionViewDelegateFlowLayout>

@property (strong, nonatomic) UIView *cardBackgroundView;
@property (strong, nonatomic) UICollectionView *collectionView;
@property (nonatomic, strong) UICollectionViewFlowLayout *flowLayout;
@property (nonatomic, copy) NSArray<NSString *> *items;

@end

@implementation MyViewController

static CGFloat const kMyCardOuterInset = 12.0;
static CGFloat const kMyCollectionVerticalInset = 8.0;
static CGFloat const kMyItemHeight = 56.0;
static CGFloat const kMyLineSpacing = 12.0;

- (void)viewDidLoad {
    [super viewDidLoad];
    self.title = @"我的";
    self.navigationItem.title = @"我的";
    self.view.backgroundColor = RGBA(229, 235, 233, 1);
    self.items = @[
        @"A_spport",
        @"A_setting",
        @"A_version"
    ];

    [self.view addSubview:self.cardBackgroundView];
    [self.view addSubview:self.collectionView];

    [self.cardBackgroundView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop).offset(ZOOMW(12));
        make.left.equalTo(self.view).offset(ZOOMW(kMyCardOuterInset));
        make.right.equalTo(self.view).offset(ZOOMW(-kMyCardOuterInset));
        make.height.mas_equalTo([self cardHeight]);
    }];

    [self.collectionView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.cardBackgroundView).insets(UIEdgeInsetsMake(ZOOMW(kMyCollectionVerticalInset), 0, ZOOMW(kMyCollectionVerticalInset), 0));
    }];
}

#pragma mark - UICollectionView DataSource & Delegate
- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.items.count;
}

- (UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    MyCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"Cell" forIndexPath:indexPath];
    NSString *imageName = self.items[indexPath.item];
    [cell configureWithImage:imageName];
    return cell;
}

- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {
    if (indexPath.item == 0) {
#if ENABLE_FEEDBACK
        FeedbackViewController *fVC = [[FeedbackViewController alloc] init];
        fVC.hidesBottomBarWhenPushed = YES;
        [self.navigationController pushViewController:fVC animated:YES];
#else
        ServiceViewController *sVC = [[ServiceViewController alloc] init];
        sVC.hidesBottomBarWhenPushed = YES;
        [self.navigationController pushViewController:sVC animated:YES];
#endif
    } else if (indexPath.item == 1) {
        SettingViewController *sVC = [[SettingViewController alloc] init];
        sVC.hidesBottomBarWhenPushed = YES;
        [self.navigationController pushViewController:sVC animated:YES];
    }
}

- (CGSize)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout sizeForItemAtIndexPath:(NSIndexPath *)indexPath {
    CGFloat horizontalInset = ZOOMW(16);
    CGFloat width = kScreenWidth - horizontalInset * 2;
    return CGSizeMake(width, ZOOM(56));
}

- (UIEdgeInsets)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout insetForSectionAtIndex:(NSInteger)section {
    return UIEdgeInsetsMake(0, ZOOMW(16), 0, ZOOMW(16));
}

- (CGFloat)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout minimumLineSpacingForSectionAtIndex:(NSInteger)section {
    return ZOOMW(kMyLineSpacing);
}

- (CGFloat)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout minimumInteritemSpacingForSectionAtIndex:(NSInteger)section {
    return 0;
}

#pragma mark - Lazy Loading
- (UICollectionViewFlowLayout *)flowLayout {
    if (!_flowLayout) {
        _flowLayout = [[UICollectionViewFlowLayout alloc] init];
    }
    return _flowLayout;
}

- (UICollectionView *)collectionView {
    if (!_collectionView) {
        _collectionView = [[UICollectionView alloc] initWithFrame:CGRectZero collectionViewLayout:self.flowLayout];
        _collectionView.dataSource = self;
        _collectionView.delegate = self;
        _collectionView.backgroundColor = [UIColor clearColor];
        _collectionView.alwaysBounceVertical = YES;
        _collectionView.showsVerticalScrollIndicator = NO;

        [_collectionView registerClass:[MyCell class] forCellWithReuseIdentifier:@"Cell"];
    }
    return _collectionView;
}

- (UIView *)cardBackgroundView {
    if (!_cardBackgroundView) {
        _cardBackgroundView = [[UIView alloc] init];
        _cardBackgroundView.backgroundColor = WHITE_COLOR;
        _cardBackgroundView.layer.cornerRadius = ZOOMW(16);
        _cardBackgroundView.layer.masksToBounds = YES;
    }
    return _cardBackgroundView;
}

- (CGFloat)cardHeight {
    NSInteger itemCount = self.items.count;
    if (itemCount <= 0) {
        return ZOOM(0);
    }
    CGFloat itemsHeight = ZOOM(kMyItemHeight) * itemCount;
    CGFloat spacingHeight = ZOOMW(kMyLineSpacing) * MAX(itemCount - 1, 0);
    CGFloat verticalInset = ZOOMW(kMyCollectionVerticalInset) * 2;
    return itemsHeight + spacingHeight + verticalInset;
}

@end

